export interface StoryCharacter {
    id: string;
    name: string;
    avatar: string;
    description: string;
    stats: {
        hp: number;
        mp: number;
        attack: number;
        defense: number;
        speed: number;
    };
    skills: string[];
    backstory: string;
}

export interface StoryScene {
    id: string;
    title: string;
    description: string;
    location: string;
    npcs: string[];
    events: string[];
}

export interface StoryScript {
    id: string;
    title: string;
    cover: string;
    description: string;
    difficulty: 'easy' | 'normal' | 'hard' | 'nightmare';
    estimatedTime: string;
    tags: string[];
    characters: StoryCharacter[];
    scenes: StoryScene[];
    openingNarrative: string;
    systemPrompt: string;
    rewards: {
        gold: number;
        exp: number;
        items: string[];
    };
}

export interface StoryProgress {
    storyId: string;
    characterId: string;
    currentScene: string;
    flags: Record<string, unknown>;
    completedScenes: string[];
    startedAt: number;
    lastPlayedAt: number;
}

